@register.simple_tag
def octicon(name, classes="w-4 h-4", title=""):
    """Render an inline GitHub Octicon SVG.

    Usage: {% octicon "globe" classes="w-5 h-5 text-sky-600" %}
    """
    body = _OCTICONS.get(name)
    if not body:
        return ""
    title_markup = f'<title>{title}</title>' if title else ""
    role_attrs = 'role="img" aria-label="{0}"'.format(title) if title else 'aria-hidden="true"'
    svg = (
        f'<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 16 16" '
        f'fill="currentColor" class="{classes}" {role_attrs}>'
        f'{title_markup}{body}</svg>'
    )
    return mark_safe(svg)


@register.filter
def currency(value):
    try:
        return f"£{float(value):.2f}"
    except (ValueError, TypeError):
        return value


@register.filter
def zip_lists(a, b):
    """Zip two lists together: {{ list_a|zip_lists:list_b }}"""
    return zip(a, b)


@register.filter
def list_max(values):
    """Return max of an iterable, 0 if empty: {{ values|list_max }}"""
    try:
        return max(values) if values else 0
    except (TypeError, ValueError):
        return 0


@register.filter
def pct_of(value, total):
    """Return value as percentage of total (0-100): {{ value|pct_of:total }}"""
    try:
        if not total:
            return 0
        return round((float(value) / float(total)) * 100)
    except (TypeError, ValueError, ZeroDivisionError):
        return 0


@register.filter
def split(value, sep=","):
    """Split a string by sep: {{ value|split:'|' }}"""
    try:
        return value.split(sep)
    except AttributeError:
        return []
